    "*[_type == \"labTest\" && slug.current == $slug][0]{\n  _id,\n  name,\n  slug,\n  description,\n  price,\n  originalPrice,\n  discount,\n  illustration,\n  body,\n  order\n}": LabTestBySlugQueryResult;
